import React from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { ArrowLeft } from 'lucide-react';
import '../styles/Katalog.css';

const Login = ({ setIsLoggedIn }) => { // Tambahkan parameter ini
  const navigate = useNavigate();

  const handleLoginSubmit = (e) => {
    e.preventDefault();
    setIsLoggedIn(true); // Mengubah status menjadi sudah login
    navigate('/keranjang'); // Mengarahkan kembali ke keranjang
  };

  return (
    <div className="katalog-wrapper" style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '100vh' }}>
      <div className="katalog-overlay"></div>
      <div style={{ position: 'relative', zIndex: 10, background: 'white', padding: '40px', borderRadius: '12px', width: '100%', maxWidth: '400px', boxShadow: '0 10px 25px rgba(0,0,0,0.2)' }}>
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', position: 'relative', marginBottom: '25px' }}>
          <ArrowLeft size={24} style={{ position: 'absolute', left: 0, cursor: 'pointer', color: '#111' }} onClick={() => navigate(-1)} />
          <div style={{ background: '#fed7aa', color: '#c2410c', padding: '6px 12px', fontWeight: 'bold', borderRadius: '4px', fontSize: '14px' }}>CampBread</div>
        </div>
        <div style={{ textAlign: 'center', marginBottom: '30px' }}>
          <h2 style={{ margin: '0 0 8px 0', fontSize: '22px', color: '#111' }}>Masuk ke Akun</h2>
          <p style={{ margin: 0, fontSize: '13px', color: '#6b7280' }}>Silakan masuk untuk melanjutkan pesanan</p>
        </div>
        <form onSubmit={handleLoginSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
          <div>
            <label style={{ display: 'block', fontSize: '12px', fontWeight: 'bold', color: '#374151', marginBottom: '6px' }}>Email atau Nomor HP</label>
            <input type="text" placeholder="Contoh: nama@email.com" required style={{ width: '100%', padding: '12px 15px', border: '1px solid #d1d5db', borderRadius: '6px', fontSize: '13px', outline: 'none', boxSizing: 'border-box' }} />
          </div>
          <div>
            <label style={{ display: 'block', fontSize: '12px', fontWeight: 'bold', color: '#374151', marginBottom: '6px' }}>Kata Sandi</label>
            <input type="password" placeholder="********" required style={{ width: '100%', padding: '12px 15px', border: '1px solid #d1d5db', borderRadius: '6px', fontSize: '13px', outline: 'none', boxSizing: 'border-box' }} />
          </div>
          <button type="submit" style={{ width: '100%', padding: '14px', background: '#b45309', color: 'white', border: 'none', borderRadius: '6px', fontSize: '14px', fontWeight: 'bold', cursor: 'pointer', marginTop: '10px' }}>Masuk Sekarang</button>
        </form>
        <div style={{ textAlign: 'center', marginTop: '25px', fontSize: '13px', color: '#6b7280' }}>
          Belum punya akun? <Link to="#" style={{ color: '#3b82f6', textDecoration: 'none', fontWeight: '600' }}>Daftar</Link>
        </div>
      </div>
    </div>
  );
};

export default Login;
